import { ICustomField } from '@domain/customField';
import { ConditionalWrapper } from '@ui/components/templates/ConditionalWrapper';
import DOMPurify from 'dompurify';
import { useEffect } from 'react';
import { FieldError, useFormContext } from 'react-hook-form';
import { FormSingleCheckboxControl } from '../CheckboxControl/FormSingleCheckboxControl';
import { FormGroup } from '../FormGroup';
import { Label } from '../Label';

type Props = {
  customField: ICustomField;
  isReadOnly?: boolean;
  isRequired?: boolean;
  name: string;
};

export const RequirementCustomField = ({ customField, isReadOnly, isRequired, name }: Props) => {
  const { formState, register, setValue } = useFormContext();
  const { helpText } = customField ?? {};

  const customFieldId = name?.split('.')?.[1] as keyof FieldError;
  const hasError = !!formState?.errors?.customFieldResponsesAttributes?.[customFieldId];

  useEffect(() => {
    if (!isRequired) {
      setValue(name, true);
    }
  }, [isRequired, name, setValue]);

  return (
    <FormGroup className="!mb-2">
      <ConditionalWrapper
        condition={isRequired}
        wrapper={
          <FormSingleCheckboxControl
            formControlProps={{ className: '!mb-0' }}
            formHelperText={helpText}
            inputClassName={hasError ? 'border-red-500 border' : ''}
            isReadOnly={isReadOnly}
            isRequired={isRequired}
            {...register(name)}
          />
        }
      >
        <div className="flex">
          <Label
            className={hasError ? 'leading-[24px] text-red-500' : 'leading-[24px]'}
            variant="bold"
          >
            By submitting this form, I agree to the following:
          </Label>
          {isRequired && <span className="relative ms-1 leading-[24px] text-red-500">*</span>}
        </div>
      </ConditionalWrapper>
      <div
        className="&>a:hover:underline &>a:text-blue-600 &>ul:ml-4 &>ol:ml-4 prose mt-1 leading-[1.5]"
        dangerouslySetInnerHTML={{
          __html: DOMPurify.sanitize(customField?.options.value || ''),
        }}
      />
    </FormGroup>
  );
};
